import java.net.URI
import java.net.http.HttpClient
import java.net.http.HttpRequest
import java.net.http.HttpResponse
import groovy.json.JsonOutput

def token = '__TELEGRAM_BOT_TOKEN__'
def chatId = '__TELEGRAM_CHAT_ID__'
def subj = message.getSubject()
def body = message.getBody()
def text = (subj ? subj + "\n\n" : "") + (body ?: "")
if (text.length() > 3900) {
    text = text.substring(0, 3900) + "\n... (truncado)"
}
def payload = JsonOutput.toJson([chat_id: chatId, text: text])
def client = HttpClient.newHttpClient()
def request = HttpRequest.newBuilder()
        .uri(URI.create("https://api.telegram.org/bot" + token + "/sendMessage"))
        .header("Content-Type", "application/json")
        .POST(HttpRequest.BodyPublishers.ofString(payload))
        .build()
def response = client.send(request, HttpResponse.BodyHandlers.ofString())
if (response.statusCode() != 200) {
    throw new RuntimeException("Telegram notify failed HTTP " + response.statusCode() + ": " + response.body())
}
